def utc_now_iso():
    return datetime.utcnow().isoformat(timespec="milliseconds") + "Z"


def build_connection_parameters(host, port, vhost, user, password, heartbeat=60, blocked_connection_timeout=300):
    credentials = pika.PlainCredentials(user, password)
    return pika.ConnectionParameters(
        host=host,
        port=port,
        virtual_host=vhost,
        credentials=credentials,
        heartbeat=heartbeat,
        blocked_connection_timeout=blocked_connection_timeout,
        connection_attempts=3,
        retry_delay=2,
    )


def declare_queue(channel, queue_name, durable=True):
    channel.queue_declare(queue=queue_name, durable=durable)


def publisher(args):
    params = build_connection_parameters(args.host, args.port, args.vhost, args.user, args.password)
    connection = pika.BlockingConnection(params)
    channel = connection.channel()
    declare_queue(channel, args.queue, durable=True)

    try:
        count = args.count
        interval = args.interval
        sent = 0

        while True:
            if count is not None and sent >= count:
                break

            task_id = str(uuid.uuid4())
            payload = {
                "task_id": task_id,
                "task_type": args.task_type,
                "payload": args.payload,
                "created_at": utc_now_iso(),
            }
            body = json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")

            props = pika.BasicProperties(
                content_type="application/json",
                delivery_mode=2,
                message_id=task_id,
                timestamp=int(time.time()),
                type=args.task_type,
            )

            channel.basic_publish(
                exchange="",
                routing_key=args.queue,
                body=body,
                properties=props,
                mandatory=False,
            )

            sent += 1
            if not args.quiet:
                print(f"published task_id={task_id} queue={args.queue}", flush=True)

            if interval > 0:
                time.sleep(interval)

    finally:
        try:
            connection.close()
        except Exception:
            pass


def consumer(args):
    stop_event = threading.Event()

    def _handle_signal(signum, frame):
        stop_event.set()

    signal.signal(signal.SIGINT, _handle_signal)
    signal.signal(signal.SIGTERM, _handle_signal)

    params = build_connection_parameters(args.host, args.port, args.vhost, args.user, args.password, heartbeat=30)
    connection = pika.BlockingConnection(params)
    channel = connection.channel()
    declare_queue(channel, args.queue, durable=True)
    channel.basic_qos(prefetch_count=args.prefetch)

    def process_task(task):
        if args.simulate_work_ms > 0:
            time.sleep(args.simulate_work_ms / 1000.0)
        if not args.quiet:
            print(f"processed task_id={task.get('task_id')} type={task.get('task_type')} created_at={task.get('created_at')}", flush=True)

    def on_message(ch, method, properties, body):
        try:
            if properties and properties.content_type == "application/json":
                task = json.loads(body.decode("utf-8"))
            else:
                task = {"task_id": properties.message_id if properties else None, "raw": body.decode("utf-8", errors="replace")}
            process_task(task)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            if not args.quiet:
                print(f"error processing message: {e}", file=sys.stderr, flush=True)
            if args.requeue_on_error:
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            else:
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    consumer_tag = channel.basic_consume(queue=args.queue, on_message_callback=on_message, auto_ack=False)

